import{_ as a,c as t,o as e,O as r}from"./chunks/framework.2ed03d8f.js";const _=JSON.parse('{"title":"Rust 入门","description":"","frontmatter":{},"headers":[],"relativePath":"rust/basic.md","filePath":"rust/basic.md"}'),s={name:"rust/basic.md"},l=r('<h1 id="rust-入门" tabindex="-1">Rust 入门 <a class="header-anchor" href="#rust-入门" aria-label="Permalink to &quot;Rust 入门&quot;">​</a></h1><p>一门赋予每个人，构建可靠且高效软件能力的语言。</p><h2 id="为什么选择-rust" tabindex="-1">为什么选择 Rust ？ <a class="header-anchor" href="#为什么选择-rust" aria-label="Permalink to &quot;为什么选择 Rust ？&quot;">​</a></h2><ul><li>高性能 - Rust 速度惊人且内存利用率极高。由于没有运行时和垃圾回收，它能够胜任对性能要求特别高的服务，可以在嵌入式设备上运行，还能轻松和其他语言集成。</li><li>可靠性 - Rust 丰富的类型系统和所有权模型保证了内存安全和线程安全，让您在编译期就能够消除各种各样的错误。</li><li>生产力 - Rust 拥有出色的文档、友好的编译器和清晰的错误提示信息， 还集成了一流的工具 —— 包管理器和构建工具，智能地自动补全和类型检验的多编辑器支持， 以及自动格式化代码等等。</li></ul><h2 id="用-rust-构建应用" tabindex="-1">用 Rust 构建应用 <a class="header-anchor" href="#用-rust-构建应用" aria-label="Permalink to &quot;用 Rust 构建应用&quot;">​</a></h2><ul><li>命令行程序</li><li>WebAssembly 应用</li><li>网络服务器</li><li>嵌入式设备</li></ul><h2 id="rust-数据类型" tabindex="-1">Rust 数据类型 <a class="header-anchor" href="#rust-数据类型" aria-label="Permalink to &quot;Rust 数据类型&quot;">​</a></h2><ul><li>整数类型</li><li>浮点类型</li><li>布尔类型</li><li>字符类型</li><li>复合类型 <ul><li>元组用一对 <code>()</code> 包括的一组数据，可以包含不同种类的数据</li><li>数组用一对 <code>[]</code> 包括的同类型数据</li></ul></li></ul><h2 id="rust-所有权" tabindex="-1">Rust 所有权 <a class="header-anchor" href="#rust-所有权" aria-label="Permalink to &quot;Rust 所有权&quot;">​</a></h2><h2 id="rust-结构体" tabindex="-1">Rust 结构体 <a class="header-anchor" href="#rust-结构体" aria-label="Permalink to &quot;Rust 结构体&quot;">​</a></h2><h2 id="rust-组织管理" tabindex="-1">Rust 组织管理 <a class="header-anchor" href="#rust-组织管理" aria-label="Permalink to &quot;Rust 组织管理&quot;">​</a></h2><p>三个重要的组织概念：箱(Crate)、包(Package)、模块(Module)</p><h2 id="rust-错误处理" tabindex="-1">Rust 错误处理 <a class="header-anchor" href="#rust-错误处理" aria-label="Permalink to &quot;Rust 错误处理&quot;">​</a></h2><p>程序中一般会出现两种错误：可恢复错误和不可恢复错误。</p><p>对于可恢复错误用 <code>Result&lt;T, E&gt;</code> 类来处理，对于不可恢复错误使用 <code>panic!</code> 宏来处理。</p><h2 id="rust-泛型与特性" tabindex="-1">Rust 泛型与特性 <a class="header-anchor" href="#rust-泛型与特性" aria-label="Permalink to &quot;Rust 泛型与特性&quot;">​</a></h2><h2 id="rust-生命周期" tabindex="-1">Rust 生命周期 <a class="header-anchor" href="#rust-生命周期" aria-label="Permalink to &quot;Rust 生命周期&quot;">​</a></h2><h2 id="rust-面向对象" tabindex="-1">Rust 面向对象 <a class="header-anchor" href="#rust-面向对象" aria-label="Permalink to &quot;Rust 面向对象&quot;">​</a></h2><h3 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h3><p><a href="https://www.rust-lang.org/" target="_blank" rel="noreferrer">Rust 官网</a></p>',20),i=[l];function u(o,h,d,n,c,b){return e(),t("div",null,i)}const q=a(s,[["render",u]]);export{_ as __pageData,q as default};
